// // This module implements a conditional OR gate instead of an XOR gate
module top_module(
    Y ,
    A1,
    A2,
    B1
);output Y ;
    input  A1;
    input  A2;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign Y = (B1 == 1'b0) ? 1'b0 : (A1 ^ A2);

endmodule
